-- grievance_channels
insert into public.grievance_channels (tier_no, forum_name, access_method, time_limit, max_compensation, scope, next_escalation_id, is_active)
select 1, 'Insurer''s Grievance Redressal Officer (GRO)', 'Contact insurer directly in writing/email/phone; insurer must acknowledge within 3 working days', '14 days to resolve from date of complaint', 'As per policy terms and insurer''s discretion', 'All insurance complaints across life, health, general. Mandatory first step — ombudsman requires proof GRO was approached first', (select id from public.grievance_channels where tier_no = 2 limit 1), true
where not exists (select 1 from public.grievance_channels where tier_no = 1);
insert into public.grievance_channels (tier_no, forum_name, access_method, time_limit, max_compensation, scope, next_escalation_id, is_active)
select 2, 'IRDAI Bima Bharosa (formerly IGMS)', 'Online at irdai.gov.in | Toll-free: 1800-4254-732 | Walk-in at IRDAI offices', 'IRDAI monitors and tracks resolution; no fixed statutory deadline but operationally within 30 days', 'IRDAI-directed resolution; can direct insurer to settle', 'All insurance complaints unresolved at Tier 1; IRDAI can issue directives to insurers; escalation point before formal adjudication', (select id from public.grievance_channels where tier_no = 3 limit 1), true
where not exists (select 1 from public.grievance_channels where tier_no = 2);
insert into public.grievance_channels (tier_no, forum_name, access_method, time_limit, max_compensation, scope, next_escalation_id, is_active)
select 3, 'Insurance Ombudsman (Bima Lokpal)', 'Online: cioins.co.in | 17 offices across India in major cities | Free service; no fees', 'Complaint must be filed within 1 year of insurer''s final rejection / 1 year of no GRO response', 'Binding award on insurer up to ₹50 lakh; complainant may reject award and go to court', 'Personal lines insurance disputes — individuals and HUFs (not corporate). Disputes up to ₹50 lakh coverage amount. Award is binding on insurer; complainant retains right to reject and escalate', (select id from public.grievance_channels where tier_no = 4 limit 1), true
where not exists (select 1 from public.grievance_channels where tier_no = 3);
insert into public.grievance_channels (tier_no, forum_name, access_method, time_limit, max_compensation, scope, next_escalation_id, is_active)
select 4, 'Consumer Forum (District / State / National Commission)', 'Online via e-Daakhil portal (edaakhil.nic.in) | No court fees for claims up to ₹5 crore | Can file personally without lawyer', 'As per Consumer Protection Act 2019; District: up to ₹50L; State: up to ₹2Cr; National: above ₹2Cr', 'Unlimited compensation + damages for mental agony + litigation costs + punitive damages for gross negligence', 'Deficiency of service; mis-selling; wrongful claim denial; unfair trade practices (ULIP sold as FD). Both individuals and companies can file. Product liability applicable to mis-selling insurers', (select id from public.grievance_channels where tier_no = 5 limit 1), true
where not exists (select 1 from public.grievance_channels where tier_no = 4);
insert into public.grievance_channels (tier_no, forum_name, access_method, time_limit, max_compensation, scope, next_escalation_id, is_active)
select 5, 'Civil Court / High Court', 'File through a licensed advocate; court fees apply; jurisdiction based on contract or defendant location', 'As per Limitation Act periods; typically 3 years from cause of action', 'Unlimited — court discretion; includes damages, interest, costs', 'Complex disputes requiring discovery; fraud cases; very large commercial claims exceeding ombudsman jurisdiction; disputes involving non-personal policyholders; cases requiring injunctions or declaratory relief', null, true
where not exists (select 1 from public.grievance_channels where tier_no = 5);
update public.grievance_channels set next_escalation_id = (select id from public.grievance_channels where tier_no = 2 limit 1) where tier_no = 1;
update public.grievance_channels set next_escalation_id = (select id from public.grievance_channels where tier_no = 3 limit 1) where tier_no = 2;
update public.grievance_channels set next_escalation_id = (select id from public.grievance_channels where tier_no = 4 limit 1) where tier_no = 3;
update public.grievance_channels set next_escalation_id = (select id from public.grievance_channels where tier_no = 5 limit 1) where tier_no = 4;

